easy.solution:
// TypeScript implementation for TypeScript Interfaces
interface TypeScriptInterfacesPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processTypeScriptInterfaces(item: TypeScriptInterfacesPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processTypeScriptInterfaces({ id: 1, title: 'TypeScript Interfaces', status: 'active' }));

